package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.io.IOException;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class LexerTest {

    private Lexer lexer;
    private ExtendedBufferedReader inMock;

    @BeforeEach
    void setUp() throws Exception {
        inMock = mock(ExtendedBufferedReader.class);
        lexer = new Lexer(CSVFormat.DEFAULT, null) {
            @Override
            Token nextToken(Token reusableToken) {
                return null; // dummy implementation for abstract method
            }
        };
        // Inject the mock into the private final 'in' field of Lexer using reflection
        Field inField = Lexer.class.getDeclaredField("in");
        inField.setAccessible(true);

        // Remove final modifier on 'in' field before setting it
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(inField, inField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        inField.set(lexer, inMock);
    }

    @Test
    void testGetLineNumber() throws IOException {
        when(inMock.getLineNumber()).thenReturn(123L);
        long lineNumber = lexer.getLineNumber();
        assertEquals(123L, lineNumber);
    }
}
